use Storable qw(nstore retrieve);

# Create a new session
sub create_session {
    my ($session_data) = @_;

    # Generate a unique session ID
    my $session_id = generate_unique_id();

    # Serialize the session data with Storable's nstore() function
    nstore($session_data, "/tmp/sess_$session_id");

    return $session_id;
}

# Load a session from a file
sub load_session {
    my ($session_id) = @_;

    # Deserialize the session data with Storable's retrieve() function
    my $session_data = retrieve("/tmp/sess_$session_id");

    return $session_data;
}

# Generate a unique ID for a new session
sub generate_unique_id {
    # Use the time and a random number to generate a unique ID
    my $time = time();
